const campainId = 1;
const startTime = $('Start and End Time Date').first().json.startTime;
const endTime = $('Start and End Time Date').first().json.endTime;
const id = $('Get last id').first().json.id;

let parameters = {
  idCampanha: campainId,
  periodoInicial: startTime,
  periodoFinal: endTime,
  // ultimosMinutos: 80,
  ...(id && { ultimoId: id })
}

return {parameters};

const calls_complete = $('Get Calls').first().json.ligacoesDetalhadas;

const calls = calls_complete.filter((item) => {
  return (item.tipoAgenda !== "" && item.tabulacao !== "" && item.categoriaTabulacao !== "") && (item.tabulacao !== "NÃO TABULADO" && item.categoriaTabulacao !== "NÃO TABULADO");
});

const states = $('Select all states').all();
const blockSize = 1000;
const quantity = calls.length;
const blocks = Math.ceil(quantity / blockSize);

let result = [];

function getDdd(number) {
  const phoneNumberStr = number.toString();
  return phoneNumberStr.slice(0, 2)
}

function getStateId(number) {
  if (number && number != '' ) {
    const ddd = getDdd(number);
    const state = states.find(state => state.json.ddds.includes(ddd));
    return state ? state.json.id : null
  }
  return null
}

function nuuabled(item) {
  if (!item) {
    return "NULL"; 
  }

  if (typeof(item) == "string") {
      if (item != "") {
          return `'${item}'`;
      }
      return "NULL";
  }

  if (typeof(item) == "undefined") {
      return "NULL";
  }
  return item;
}

for (let i = 0; i < blocks; i++) {   

  const start = i * blockSize;
  const end = start + blockSize;
  const block = calls.slice(start, end);
  const insertString = block.map((item) => {

      return `(` +
      `${nuuabled(item.idLigacao)},` +
      `${nuuabled(new Date(item.dataHoraLigacao).toISOString().split('T')[0] + ' ' + new Date(item.dataHoraLigacao).toTimeString().split(' ')[0].slice(0, -3) + ':00')},` +
      `${nuuabled(item.nrLead)},` +
      `${nuuabled(item.resultadoLigacao)},` +
      `${nuuabled(item.tempoSegundos)},` +
      `${nuuabled(item.telefone)},` +
      `${nuuabled(item.idLote)},` +
      `${nuuabled(item.nomeCliente)},` +
      `${nuuabled(new Date(item.dataImportacao).toISOString().split('T')[0] + ' ' + new Date(item.dataImportacao).toTimeString().split(' ')[0].slice(0, -3) + ':00')},` +
      `${nuuabled(item.codCliente)},` +
      `${nuuabled(item.idGrupoUsuario)},` +
      `${nuuabled(item.grupoOrigem)},` +
      `${nuuabled(item.idUsuario)},` +
      `${nuuabled(item.usuarioOperador)},` +
      `${nuuabled(item.statusAtendimento)},` +
      `${nuuabled(item.tipoAgenda)},` +
      `${nuuabled(item.tabulacao)},` +
      `${nuuabled(item.categoriaTabulacao)},` +
      `${nuuabled(getStateId(item.telefone))}`+
      `)`;
  }).join(',');

  result.push(insertString);
}

return {result: result};
